  }
}

import { supabase } from '../supabaseClient.ts';
import { User, AuditLog } from '../../types/index';

/**
 * Tenta obter o IP público do cliente. 
 * Nota: Em produção, isso geralmente é feito via Headers no Backend (Edge Functions),
 * mas para um MVP frontend-only, usamos um lookup externo.
 */
const getClientIp = async (): Promise<string> => {
    try {
        const response = await fetch('https://api.ipify.org?format=json');
        const data = await response.json();
        return data.ip;
    } catch (e) {
        return '0.0.0.0 (Local/Proxy)';
    }
};

const getDeviceAndLocation = () => {
    const userAgent = navigator.userAgent;
    let device = 'Desktop';
    if (/Mobi|Android/i.test(userAgent)) device = 'Mobile';
    if (/Tablet|iPad/i.test(userAgent)) device = 'Tablet';

    // Simplificação para o MVP
    const platform = navigator.platform;
    const language = navigator.language;

    return { 
        userAgent, 
        device, 
        location: `Inferred (${language}/${platform})`,
        details: { platform, language }
    };
};

export const logAction = async (
    user: User | null, 
    action: string, 
    target: string, 
    category: AuditLog['category'],
    severity: AuditLog['severity'] = 'INFO',
    status: AuditLog['status'] = 'SUCCESS',
    metadata: Record<string, any> = {}
) => {
    try {
        const { userAgent, device, location, details } = getDeviceAndLocation();
        const ip = await getClientIp();
        const requestId = crypto.randomUUID();

        await supabase.from('audit_logs').insert({
            user_id: user?.id || null,
            action,
            target,
            category,
            severity,
            status,
            ip,
            location,
            user_agent: userAgent,
            device,
            metadata: { 
                userName: user?.name || 'Sistema/Anônimo', 
                userRole: user?.role || 'SYSTEM', 
                browserDetails: details,
                ...metadata 
            },
            request_id: requestId,
        });
    } catch (e) {
        console.error("Erro crítico ao registrar log de auditoria:", e);
    }
};

import { User, UserRole, AccountStatus } from '../../types/auth.ts';
import { IUserService, RawProfile } from './interfaces.ts';
import { supabase } from '../supabaseClient.ts';
import { logAction } from './loggingService.ts';
import { normalizeRole } from '../mappers/roleMapper.ts';
import { withTimeout } from '../utils/apiUtils.ts';
import { withAuditLog } from '../utils/auditLogWrapper.ts';
import { AuthError, Session, UserResponse, PostgrestSingleResponse, PostgrestResponse } from '@supabase/supabase-js';

const API_TIMEOUT = 8000;

const toDomainUser = (row: RawProfile | null, sessionEmail?: string): User | null => {
  if (!row) return null;
  const orgData = Array.isArray(row.organizations) ? row.organizations[0] : row.organizations;

  return {
    id: row.id,
    name: row.full_name || 'Usuário Sem Nome',
    email: row.email || sessionEmail || '',
    role: normalizeRole(row.role),
    organizationId: row.organization_id || undefined,
    organizationName: orgData?.name || 'Aços Vital (Interno)',
    status: (row.status as AccountStatus) || AccountStatus.ACTIVE,
    department: row.department || undefined,
    lastLogin: row.last_login || undefined
  };
};

export const SupabaseUserService: IUserService = {
  authenticate: async (email, password) => {
    try {
      const authPromise = supabase.auth.signInWithPassword({
        email: email.trim().toLowerCase(),
        password
      });

      const result: { data: { session: Session | null }; error: AuthError | null } = await withTimeout(
        authPromise,
        API_TIMEOUT,
        "Tempo esgotado ao autenticar. Verifique sua conexão."
      );
      const { data, error } = result;

      if (error) {
        // Log de falha de tentativa de acesso (anônimo)
        await logAction(null, 'LOGIN_ATTEMPT_FAILED', email, 'AUTH', 'WARNING', 'FAILURE', { reason: error.message });
        return { 
          success: false, 
          error: error.message === "Invalid login credentials" 
            ? "E-mail ou senha incorretos." 
            : "Falha na autenticação."
        };
      }

      return { success: true };
    } catch (e: any) {
      return { success: false, error: e.message || "Erro de conexão." };
    }
  },

  signUp: async (email, password, fullName, organizationId, department, role = UserRole.QUALITY) => {
    const authPromise = supabase.auth.signUp({ 
        email: email.trim().toLowerCase(), 
        password 
      });
    const authResult: { data: { user: UserResponse['user'] | null }; error: AuthError | null } = await withTimeout( 
      authPromise,
      API_TIMEOUT,
      "Tempo esgotado ao registrar usuário."
    );
    const { data, error: authError } = authResult;

    if (authError) throw authError;

    if (data.user) {
      const profilePromise: Promise<PostgrestResponse<null>> = supabase.from('profiles').upsert({
          id: data.user.id,
          full_name: fullName.trim(),
          email: email.trim().toLowerCase(),
          organization_id: organizationId || null,
          department: department || null,
          role: role,
          status: 'ACTIVE'
        });
      const profileResult = await withTimeout( 
        profilePromise,
        API_TIMEOUT,
        "Tempo esgotado ao criar perfil."
      );
      const { error: profileError } = profileResult;

      if (profileError) {
        throw new Error("Usuário criado, mas houve um erro ao configurar o perfil.");
      }

      // Log de criação de novo usuário
      await logAction(null, 'USER_SIGNUP', email, 'AUTH', 'INFO', 'SUCCESS', { fullName, role });
    }
  },

  getCurrentUser: async () => {
    try {
      const sessionResult: { data: { session: Session | null }; error: AuthError | null } = await withTimeout( 
        supabase.auth.getSession(),
        API_TIMEOUT,
        "Tempo esgotado ao buscar sessão de usuário."
      );
      const { data: { session } } = sessionResult;
      if (!session?.user) return null;

      const profileQuery = supabase
        .from('profiles')
        .select('*, organizations!organization_id(name)')
        .eq('id', session.user.id)
        .maybeSingle();

      const profileFetchResult: PostgrestSingleResponse<RawProfile> = await withTimeout( 
        profileQuery,
        API_TIMEOUT,
        "Tempo esgotado ao buscar perfil do usuário."
      );
      const { data: profile, error } = profileFetchResult;

      if (error || !profile) return null;

      return toDomainUser(profile, session.user.email);
    } catch (e: any) {
      return null;
    }
  },

  logout: async () => {
    const result: { error: AuthError | null } = await withTimeout( 
      supabase.auth.signOut(),
      API_TIMEOUT,
      "Tempo esgotado ao fazer logout."
    );
    const { error } = result;
    if (error) throw error;
    localStorage.clear();
  },

  getUsers: async () => {
    const usersPromise: Promise<PostgrestResponse<RawProfile>> = supabase
        .from('profiles')
        .select('*, organizations!organization_id(name)')
        .order('full_name');
    const result = await withTimeout( 
      usersPromise,
      API_TIMEOUT,
      "Tempo esgotado ao buscar usuários."
    );
    const { data, error } = result;
    if (error) throw error;
    return (data || []).map(p => toDomainUser(p) as User);
  },

  getUsersByRole: async (role) => {
    const usersByRolePromise: Promise<PostgrestResponse<RawProfile>> = supabase
        .from('profiles')
        .select('*, organizations!organization_id(name)')
        .eq('role', role);
    const result = await withTimeout( 
      usersByRolePromise,
      API_TIMEOUT,
      `Tempo esgotado ao buscar usuários por role (${role}).`
    );
    const { data, error } = result;
    if (error) throw error;
    return (data || []).map(p => toDomainUser(p) as User);
  },

  saveUser: async (u) => {
    // Implementação com Auditoria
    const action = async () => {
      const { error } = await supabase.from('profiles').update({
          full_name: u.name,
          role: u.role,
          organization_id: u.organizationId || null,
          status: u.status,
          department: u.department || null,
          updated_at: new Date().toISOString()
      }).eq('id', u.id);

      if (error) throw error;
    };

    // Logamos a atualização de perfil como uma ação de dados crítica
    await withAuditLog(null, 'USER_PROFILE_UPDATE', { 
        target: u.id, 
        category: 'DATA', 
        metadata: { email: u.email, newRole: u.role } 
    }, action);
  },

  changePassword: async (userId, current, newPass) => {
    const action = async () => {
        const { error } = await supabase.auth.updateUser({ password: newPass });
        if (error) throw error;
        return true;
    };

    // Log de segurança para alteração de senha
    return await withAuditLog(null, 'USER_PASSWORD_CHANGE', { 
        target: userId, 
        category: 'SECURITY', 
        initialSeverity: 'WARNING' 
    }, action);
  },

  deleteUser: async (id) => {
    const action = async () => {
      const { error } = await supabase.from('profiles').delete().eq('id', id);
      if (error) throw error;
    };

    await withAuditLog(null, 'USER_DELETION', { 
        target: id, 
        category: 'DATA', 
        initialSeverity: 'CRITICAL' 
    }, action);
  },

  blockUserById: async (admin, target, reason) => {
    const blockUserPromise: Promise<PostgrestResponse<null>> = supabase.from('profiles').update({ status: 'BLOCKED' }).eq('id', target);
    const result = await withTimeout( 
      blockUserPromise,
      API_TIMEOUT,
      "Tempo esgotado ao bloquear usuário."
    );
    const { error } = result;
    if (error) throw error;
    await logAction(admin, 'SEC_USER_BLOCKED', target, 'SECURITY', 'CRITICAL', 'SUCCESS', { reason });
  },

  getUserStats: async () => {
    const [totalResult, activeResult]: [PostgrestResponse<null>, PostgrestResponse<null>] = await withTimeout( 
      Promise.all([
        supabase.from('profiles').select('*', { count: 'exact', head: true }),
        supabase.from('profiles').select('*', { count: 'exact', head: true }).eq('status', 'ACTIVE')
      ]),
      API_TIMEOUT,
      "Tempo esgotado ao buscar estatísticas de usuário."
    );
    return { total: totalResult.count || 0, active: activeResult.count || 0, clients: 0 };
  },

  generateRandomPassword: () => Math.random().toString(36).slice(-10)
};

import React, { createContext, useContext, useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { supabase } from '../lib/supabaseClient';
import { userService } from '../lib/services';
import { appService } from '../lib/services/appService.tsx';
import { logAction } from '../lib/services/loggingService.ts';
import { User, SystemStatus } from '../types';

interface AuthState {
  user: User | null;
  isLoading: boolean;
  systemStatus: SystemStatus | null;
  error: string | null;
  isInitialSyncComplete: boolean;
}

interface AuthContextType extends AuthState {
  login: (email: string, password: string) => Promise<{ success: boolean; error?: string }>;
  logout: () => Promise<void>;
  retryInitialSync: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AuthState>({
    user: null,
    isLoading: true,
    systemStatus: null,
    error: null,
    isInitialSyncComplete: false,
  });

  const mounted = useRef(true);

  const refreshAuth = async () => {
    try {
      const { user, systemStatus } = await appService.getInitialData();

      if (mounted.current) {
        setState({
          user,
          systemStatus,
          isLoading: false,
          error: null,
          isInitialSyncComplete: true,
        });
      }
    } catch (error) {
      if (mounted.current) setState(s => ({ ...s, isLoading: false, error: "Erro de conexão", isInitialSyncComplete: true }));
    }
  };

  const retryInitialSync = useCallback(async () => {
    setState(s => ({ ...s, isLoading: true, error: null, isInitialSyncComplete: false }));
    await refreshAuth();
  }, []);

  useEffect(() => {
    mounted.current = true;
    refreshAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (event === 'SIGNED_IN' && session?.user) {
          // Log de login bem-sucedido
          // Nota: Como o refreshAuth é assíncrono, pegamos dados básicos da sessão
          await logAction(null, 'USER_LOGIN', session.user.email || 'unknown', 'AUTH', 'INFO', 'SUCCESS', {
              userId: session.user.id,
              authEvent: event
          });
          setState(s => ({ ...s, isLoading: true, isInitialSyncComplete: false }));
          refreshAuth();
      }

      if (event === 'SIGNED_OUT') {
          setState(s => ({ ...s, user: null, isLoading: true, isInitialSyncComplete: false }));
          refreshAuth();
      }
    });

    return () => {
      mounted.current = false;
      subscription.unsubscribe();
    };
  }, []);

  const login = async (email: string, password: string) => {
    setState(s => ({ ...s, isLoading: true }));
    const result = await userService.authenticate(email, password);

    if (!result.success) {
      setState(s => ({ ...s, isLoading: false, error: result.error || 'Erro' }));
    }
    return result;
  };

  const logout = async () => {
    // Log de logout antes de destruir a sessão
    if (state.user) {
        await logAction(state.user, 'USER_LOGOUT', state.user.email, 'AUTH', 'INFO', 'SUCCESS');
    }

    await userService.logout();
    window.location.href = '/'; 
  };

  const value = useMemo(() => ({ ...state, login, logout, retryInitialSync }), [state, retryInitialSync]);

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) throw new Error('useAuth deve ser usado dentro de AuthProvider');
  return context;
};

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertOctagon, RefreshCw } from 'lucide-react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error?: Error;
}

/**
 * Boundary de Erros do Sistema
 * Refatorado para maior estabilidade e compatibilidade com TypeScript.
 */
// Explicitly use React.Component to ensure props, state and setState are correctly inherited and visible to TypeScript.
export class ErrorBoundary extends React.Component<Props, State> {

  // State initialization inside the constructor
  constructor(props: Props) {
    super(props);
    // Standard initialization of state
    this.state = {
      hasError: false
    };
  }

  // Mandatory static method for error boundaries to update state
  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  // Catching errors for logging and analytics
  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('[Critical System Error]', error, errorInfo);
  }

  // Handler to reset error state and reload the application
  private handleReset = () => {
    // setState is inherited from React.Component
    this.setState({ hasError: false, error: undefined });
    window.location.reload();
  };

  public render(): ReactNode {
    // props and state are available through inheritance from React.Component
    if (!this.state.hasError) return this.props.children;

    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 font-sans">
        <div className="max-w-md w-full bg-white rounded-[2.5rem] shadow-2xl border border-red-100 p-10 text-center animate-in zoom-in-95 duration-300">
          <div className="w-20 h-20 bg-red-50 text-red-500 rounded-2xl flex items-center justify-center mx-auto mb-8 shadow-inner">
            <AlertOctagon size={40} />
          </div>

          <h1 className="text-2xl font-black text-slate-900 tracking-tighter mb-3">Erro de Camada Crítica</h1>
          <p className="text-slate-500 mb-10 text-sm font-medium leading-relaxed">
            Ocorreu uma exceção no processamento da interface. Se você for um desenvolvedor, verifique o console do navegador.
          </p>

          <div className="flex flex-col gap-3">
            <button
              onClick={this.handleReset}
              className="w-full flex items-center justify-center gap-3 bg-slate-900 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all active:scale-98 shadow-xl"
            >
              <RefreshCw size={16} /> Reiniciar Aplicação
            </button>
          </div>
        </div>
      </div>
    );
  }
}

import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';

/**
 * Componente utilitário que garante que o usuário retorne ao topo
 * sempre que a rota ou os parâmetros de busca mudarem.
 */
export const ScrollToTop = () => {
  const { pathname, search } = useLocation();

  useEffect(() => {
    // Reset do scroll da janela global
    window.scrollTo(0, 0);

    // Reset de containers internos de scroll (comuns em dashboards com sidebar fixa)
    const scrollableElements = document.querySelectorAll('.overflow-y-auto, main');
    scrollableElements.forEach((el) => {
      el.scrollTo({ top: 0, behavior: 'instant' });
    });
  }, [pathname, search]);

  return null;
};

