import { fileService } from '../lib/services/index.ts';
import { useTranslation } from 'react-i18next';
import { 
  FileText, 
  Loader2, 
  ShieldCheck, 
  Library, 
  AlertTriangle,
  LayoutDashboard,
  Trash2,
  XCircle,
  Clock,
  BarChart3,
  Bell
} from 'lucide-react';
