import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertOctagon, RefreshCw } from 'lucide-react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error?: Error;
}

/**
 * Boundary de Erros do Sistema
 * Refatorado para maior estabilidade e compatibilidade com TypeScript.
 */
// Fix: Inherit from Component directly to ensure proper property resolution by TypeScript
export class ErrorBoundary extends Component<Props, State> {

  // Fix: Use property initialization instead of constructor to guarantee 'state' property detection on 'this'
  public state: State = {
    hasError: false
  };

  // Mandatory static method for error boundaries to update state
  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  // Catching errors for logging and analytics
  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('[Critical System Error]', error, errorInfo);
  }

  // Handler to reset error state and reload the application
  private handleReset = () => {
    // Fix: setState is now correctly recognized as an inherited member from Component class
    this.setState({ hasError: false, error: undefined });
    window.location.reload();
  };

  public render(): ReactNode {
    // Fix: state and props are now correctly recognized as inherited members from Component class
    if (!this.state.hasError) return this.props.children;

    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 font-sans">
        <div className="max-w-md w-full bg-white rounded-[2.5rem] shadow-2xl border border-red-100 p-10 text-center animate-in zoom-in-95 duration-300">
          <div className="w-20 h-20 bg-red-50 text-red-500 rounded-2xl flex items-center justify-center mx-auto mb-8 shadow-inner">
            <AlertOctagon size={40} />
          </div>

          <h1 className="text-2xl font-black text-slate-900 tracking-tighter mb-3">Erro de Camada Crítica</h1>
          <p className="text-slate-500 mb-10 text-sm font-medium leading-relaxed">
            Ocorreu uma exceção no processamento da interface. Se você for um desenvolvedor, verifique o console do navegador.
          </p>

          <div className="flex flex-col gap-3">
            <button
              onClick={this.handleReset}
              className="w-full flex items-center justify-center gap-3 bg-slate-900 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-slate-800 transition-all active:scale-98 shadow-xl"
            >
              <RefreshCw size={16} /> Reiniciar Aplicação
            </button>
          </div>
        </div>
      </div>
    );
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  X, Download, Loader2, FileText, AlertCircle, 
  ChevronLeft, ChevronRight, Calendar, User, 
  HardDrive, Maximize2, Minimize2, ZoomIn, ZoomOut, 
  RotateCcw, ShieldCheck, Tag, Info, ExternalLink
} from 'lucide-react';
import { FileNode, FileType } from '../../../types/index.ts';
import { fileService } from '../../../lib/services/index.ts';
import { useAuth } from '../../../context/authContext.tsx';
import { useTranslation } from 'react-i18next';
import { FileStatusBadge } from './components/FileStatusBadge.tsx';
import { QualityStatus } from '../../../types/metallurgy.ts';

interface FilePreviewModalProps {
  initialFile: FileNode | null;
  allFiles: FileNode[];
  isOpen: boolean;
  onClose: () => void;
  onDownloadFile: (file: FileNode) => void;
}

/**
 * FilePreviewModal (Professional Grade Viewer)
 * Refatorado para evitar bloqueios do Chrome em visualização de PDF.
 */
export const FilePreviewModal: React.FC<FilePreviewModalProps> = ({ 
  initialFile, 
  allFiles, 
  isOpen, 
  onClose, 
  onDownloadFile 
}) => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const modalRef = useRef<HTMLDivElement>(null);

  const [currentFile, setCurrentFile] = useState<FileNode | null>(initialFile);
  const [currentIndex, setCurrentIndex] = useState<number>(-1);
  const [url, setUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Viewer States
  const [zoom, setZoom] = useState(1);
  const [showSidebar, setShowSidebar] = useState(true);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // Sincronização inicial
  useEffect(() => {
    if (isOpen && initialFile) {
      const idx = allFiles.findIndex(f => f.id === initialFile.id);
      setCurrentIndex(idx);
      setCurrentFile(initialFile);
      setZoom(1);
    }
  }, [isOpen, initialFile, allFiles]);

  // Carregamento de URL Assinada
  useEffect(() => {
    if (currentFile && user && isOpen) {
      setLoading(true);
      setError(null);
      fileService.getFileSignedUrl(user, currentFile.id)
        .then(signedUrl => setUrl(signedUrl))
        .catch(() => setError(t('files.errorLoadingDocument')))
        .finally(() => setLoading(false));
    }
  }, [currentFile, user, isOpen, t]);

  // Handlers de Navegação
  const navigateFile = useCallback((direction: 'next' | 'prev') => {
    if (allFiles.length <= 1) return;
    let newIndex = direction === 'next' 
      ? (currentIndex + 1) % allFiles.length 
      : (currentIndex - 1 + allFiles.length) % allFiles.length;

    setCurrentIndex(newIndex);
    setCurrentFile(allFiles[newIndex]);
    setZoom(1);
  }, [allFiles, currentIndex]);

  // Handlers de Visualização
  const handleZoom = (type: 'in' | 'out' | 'reset') => {
    if (type === 'in') setZoom(prev => Math.min(prev + 0.25, 3));
    else if (type === 'out') setZoom(prev => Math.max(prev - 0.25, 0.5));
    else setZoom(1);
  };

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      modalRef.current?.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  // Keyboard Shortcuts
  useEffect(() => {
    const handleKeys = (e: KeyboardEvent) => {
      if (!isOpen) return;
      if (e.key === 'ArrowRight') navigateFile('next');
      if (e.key === 'ArrowLeft') navigateFile('prev');
      if (e.key === 'Escape') onClose();
      if (e.key === '+' || e.key === '=') handleZoom('in');
      if (e.key === '-') handleZoom('out');
    };
    window.addEventListener('keydown', handleKeys);
    return () => window.removeEventListener('keydown', handleKeys);
  }, [isOpen, navigateFile, onClose]);

  if (!isOpen || !currentFile) return null;

  const isImage = currentFile.name.match(/\.(jpg|jpeg|png|webp)$/i);

  return (
    <div 
      ref={modalRef}
      className="fixed inset-0 z-[200] bg-slate-950 flex flex-col animate-in fade-in duration-300"
      role="dialog"
      aria-modal="true"
    >
      {/* Top Header */}
      <header className="h-16 shrink-0 bg-slate-900/60 backdrop-blur-xl border-b border-white/5 flex items-center justify-between px-6 z-30">
        <div className="flex items-center gap-4">
          <div className="p-2.5 bg-blue-500/10 rounded-xl">
             {isImage ? <Tag className="text-blue-400" size={20} /> : <FileText className="text-blue-400" size={20} />}
          </div>
          <div>
